mapper.sql:
select ai_device.device_id as device_id, device_name, rtsp_url, snapshot_url, identify_interval, alarm_interval, ai_group.group_id as group_id, group_name, device_lng, device_lat, ai_device.create_time, count(CASE WHEN ai_device_algorithm.status = 0 THEN 1 ELSE NULL END) as algorithm_number from ai_device left join ai_device_group on ai_device.device_id = ai_device_group.device_id left join ai_group on ai_device_group.group_id = ai_group.group_id left join ai_device_algorithm on ai_device.device_id = ai_device_algorithm.device_id
and device_name like concat('%', #{deviceName}, '%') and group_name like concat('%', #{groupName}, '%') and rtsp_url like concat('%', #{rtspUrl}, '%') and identify_interval = #{identifyInterval} and alarm_interval = #{alarmInterval} and ai_group.group_id = #{groupId} and ai_device.create_time between #{params.beginCreateTime} and #{params.endCreateTime}
group by device_id, group_id having algorithm_number = #{algorithmNumber}

mapper.update:
update ai_device_algorithm
set status = #{status}, sensitivity = #{sensitivity}, pixels = #{pixels}, alarm_times = #{alarmTimes}
where device_id = #{deviceId} and algorithm_id = #{algorithmId}
